 &lt;h1 id=&#34;yijinccctf&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#yijinccctf&#34;&gt;#&lt;/a&gt; yijincc—CTF&lt;/h1&gt;
&lt;h2 id=&#34;萌新1&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#萌新1&#34;&gt;#&lt;/a&gt; 萌新 1&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;萌新 1-MISC&lt;/p&gt;
&lt;/blockquote&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;题名&lt;/th&gt;
&lt;th&gt;思路&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;镜中秘影&lt;/td&gt;
&lt;td&gt;修改图片高度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;hand&lt;/td&gt;
&lt;td&gt;修改图片高度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;数据迷踪&lt;/td&gt;
&lt;td&gt;丢随波逐流跑就有（切换到文本格式，使用查找，搜 flag）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;洋葱&lt;/td&gt;
&lt;td&gt;查看文件二进制，看头，修改文件后缀 zip&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;blockquote&gt;
&lt;p&gt;萌新 1-WEB&lt;/p&gt;
&lt;/blockquote&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;题名&lt;/th&gt;
&lt;th&gt;思路&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;Hack the World&lt;/td&gt;
&lt;td&gt;源代码注释解密 base16&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Hack the Cipher&lt;/td&gt;
&lt;td&gt;请求头摩斯密码&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;谍影重重&lt;/td&gt;
&lt;td&gt;1. 修改按钮 disable 删掉 or 直接输入跳转链接 &amp;lt;br /&amp;gt;2. 赛博厨子 rc4 解密 key:china&amp;lt;br /&amp;gt;3. 输入 hex (16 进制)，输出改为 LATIN1 (key 同理)&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;搬家&lt;/td&gt;
&lt;td&gt;御剑扫路径，www.zip&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;萌新2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#萌新2&#34;&gt;#&lt;/a&gt; 萌新 2&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;萌新 2—MISC&lt;/p&gt;
&lt;/blockquote&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;题名&lt;/th&gt;
&lt;th&gt;思路&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;暗影图像&lt;/td&gt;
&lt;td&gt;丢随波逐流（RGB 里的 flag）&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;破损像素的暗号&lt;/td&gt;
&lt;td&gt;修改文件头修复照片&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;解压谜局&lt;/td&gt;
&lt;td&gt;kali 中的 &lt;code&gt;zip2john &lt;/code&gt;    &amp;lt;br /&amp;gt; &lt;code&gt;zip2john flag.zip &amp;gt; 1.txt&lt;/code&gt; &amp;lt;br /&amp;gt; &lt;code&gt;john 1.txt&lt;/code&gt; &amp;lt;br /&amp;gt; 密码： &lt;code&gt;password&lt;/code&gt; &amp;lt;br /&amp;gt; &lt;code&gt;rar2john flag &amp;gt; 2.txt&lt;/code&gt; &amp;lt;br /&amp;gt; 密码： &lt;code&gt;a123456&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;双生之谜&lt;/td&gt;
&lt;td&gt;图片里有两个请求头 &amp;lt;br /&amp;gt; 头： &lt;code&gt;FF D8 DD&lt;/code&gt; ，尾： &lt;code&gt;FF D9&lt;/code&gt; &amp;lt;br /&amp;gt; 选择后保存新图片&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;blockquote&gt;
