&lt;h1 id=&#34;资产安全加固&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#资产安全加固&#34;&gt;#&lt;/a&gt; 资产安全加固&lt;/h1&gt;
&lt;h2 id=&#34;windows安全基线检查加固&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#windows安全基线检查加固&#34;&gt;#&lt;/a&gt; Windows 安全基线检查加固&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;账户&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;在操作系统中，账户是操作系统进行权限管理的基本单元。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;用户&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;本地用户、域用户&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;本地用户：只能对本地计算机有效&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;域用户：对整个安全域有效&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;用户组&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ul&gt;
&lt;li&gt;由多个用户组成的一个群体&lt;/li&gt;
&lt;/ul&gt;

 &lt;h1 id=&#34;系统用法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#系统用法&#34;&gt;#&lt;/a&gt; 系统用法&lt;/h1&gt;
&lt;figure class=&#34;highlight sh&#34;&gt;&lt;figcaption data-lang=&#34;sh&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;$0&lt;/span&gt;								&lt;span class=&#34;token comment&#34;&gt;## 切换 sh&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;systemctl status firewalld.service 	&lt;span class=&#34;token comment&#34;&gt;## 查看防火墙服务&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;cat&lt;/span&gt; /etc/passwd &lt;span class=&#34;token operator&#34;&gt;|&lt;/span&gt; shadow			&lt;span class=&#34;token comment&#34;&gt;## 查看用户&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;history&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-c&lt;/span&gt;							&lt;span class=&#34;token comment&#34;&gt;## 清除 bash 历史记录&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;systemctl &lt;span class=&#34;token parameter variable&#34;&gt;--type&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;service			&lt;span class=&#34;token comment&#34;&gt;## 查看系统所有服务&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;uname&lt;/span&gt;								&lt;span class=&#34;token comment&#34;&gt;## 查看系统版本&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;网卡设置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#网卡设置&#34;&gt;#&lt;/a&gt; 网卡设置&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;开启 / 关闭网卡&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight sh&#34;&gt;&lt;figcaption data-lang=&#34;sh&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;ifconfig&lt;/span&gt; eth0 down					&lt;span class=&#34;token comment&#34;&gt;## 关闭网卡&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;ifconfig&lt;/span&gt; eth0 up					&lt;span class=&#34;token comment&#34;&gt;## 开启网卡&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;配置系统代理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#配置系统代理&#34;&gt;#&lt;/a&gt; 配置系统代理&lt;/h1&gt;
&lt;h2 id=&#34;开启代理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#开启代理&#34;&gt;#&lt;/a&gt; 开启代理&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;创建 proxy_on.sh 文件&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight sh&#34;&gt;&lt;figcaption data-lang=&#34;sh&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;touch&lt;/span&gt; proxy_on.sh&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ul&gt;
&lt;li&gt;开启代理配置&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight sh&#34;&gt;&lt;figcaption data-lang=&#34;sh&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token shebang important&#34;&gt;#!/bin/bash&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;gsettings &lt;span class=&#34;token builtin class-name&#34;&gt;set&lt;/span&gt; org.gnome.system.proxy mode &lt;span class=&#34;token string&#34;&gt;&#39;manual&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;gsettings &lt;span class=&#34;token builtin class-name&#34;&gt;set&lt;/span&gt; org.gnome.system.proxy.http &lt;span class=&#34;token function&#34;&gt;host&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;192.168.2.107&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;gsettings &lt;span class=&#34;token builtin class-name&#34;&gt;set&lt;/span&gt; org.gnome.system.proxy.http port &lt;span class=&#34;token number&#34;&gt;10809&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;gsettings &lt;span class=&#34;token builtin class-name&#34;&gt;set&lt;/span&gt; org.gnome.system.proxy.https &lt;span class=&#34;token function&#34;&gt;host&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;192.168.2.107&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;gsettings &lt;span class=&#34;token builtin class-name&#34;&gt;set&lt;/span&gt; org.gnome.system.proxy.https port &lt;span class=&#34;token number&#34;&gt;10809&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;系统代理已开启&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;关闭代理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#关闭代理&#34;&gt;#&lt;/a&gt; 关闭代理&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;11 1docker version      ## 查看版本 2docker info         ## 详细信息 3docker -h           ## 帮助文档 4docker images       ## 查看所有镜像 5docker pull 镜像名:{tar}       ## 下载镜像 6docker ps           ## 查看正在运行的镜像 7docker ps -a        ## 查看所有正在运行的容器包括以前运行的 8docker ps -n 3      ## 查看前 3 个运行的容器 9docker ps -l        ## 查看上 1 个运行的容器 10docker start 容器名称 11docker stop 容器名称 sh&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight sh&#34;&gt;&lt;figcaption data-lang=&#34;sh&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;touch&lt;/span&gt; proxy_off.sh&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ul&gt;
&lt;li&gt;关闭代理配置&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight sh&#34;&gt;&lt;figcaption data-lang=&#34;sh&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token shebang important&#34;&gt;#!/bin/bash&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;gsettings &lt;span class=&#34;token builtin class-name&#34;&gt;set&lt;/span&gt; org.gnome.system.proxy mode &lt;span class=&#34;token string&#34;&gt;&#39;none&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;系统代理已关闭&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;更新软件仓库&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#更新软件仓库&#34;&gt;#&lt;/a&gt; 更新软件仓库&lt;/h1&gt;
&lt;figure class=&#34;highlight sh&#34;&gt;&lt;figcaption data-lang=&#34;sh&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;apt-get&lt;/span&gt; update&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;windows&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#windows&#34;&gt;#&lt;/a&gt; windows&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;存放密码的目录&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-bat&#34;&gt;C:\Windows\System32\config\sam
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;存放 host 的目录&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-bat&#34;&gt;C:\Windows\System32\drivers\etc\hosts
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;查看端口 8080&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-bat&#34;&gt;netstat -ano | findstr :8080
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;隐藏文件&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-bat&#34;&gt;attrib +s +h  xxx.txt ## 系统保护并且隐藏的文件
&lt;/code&gt;&lt;/pre&gt;
&lt;ul&gt;
&lt;li&gt;注销用户&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code&gt;logoff
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;docker命令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#docker命令&#34;&gt;#&lt;/a&gt; Docker 命令&lt;/h2&gt;
&lt;figure class=&#34;highlight sh&#34;&gt;&lt;figcaption data-lang=&#34;sh&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt; version		&lt;span class=&#34;token comment&#34;&gt;## 查看版本&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt; info			&lt;span class=&#34;token comment&#34;&gt;## 详细信息&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-h&lt;/span&gt;			&lt;span class=&#34;token comment&#34;&gt;## 帮助文档&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt; images		&lt;span class=&#34;token comment&#34;&gt;## 查看所有镜像&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt; pull 镜像名:&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;tar&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;		&lt;span class=&#34;token comment&#34;&gt;## 下载镜像&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;ps&lt;/span&gt;			&lt;span class=&#34;token comment&#34;&gt;## 查看正在运行的镜像&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;ps&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-a&lt;/span&gt;		&lt;span class=&#34;token comment&#34;&gt;## 查看所有正在运行的容器包括以前运行的&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;ps&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-n&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;		&lt;span class=&#34;token comment&#34;&gt;## 查看前 3 个运行的容器&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;ps&lt;/span&gt; &lt;span class=&#34;token parameter variable&#34;&gt;-l&lt;/span&gt;		&lt;span class=&#34;token comment&#34;&gt;## 查看上 1 个运行的容器&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt; start 容器名称&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;docker&lt;/span&gt; stop 容器名称&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

